INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (34, 'Клиент Циан', 'Огромное спасибо Роману за идеальную помощь в покупке нашей квартиры! С первого звонка он взял все на себя: быстро подобрал варианты под наши пожелания (бюджет, район, планировка), организовал все просмотры без лишней суеты и даже помог с переговорами по цене. Профессионал высшего уровня, честный, пунктуальный и всегда на связи. Рекомендую всем Роман №1 в своем деле!', 5, true, '2026-04-10 00:15:51+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (35, 'Клиент Циан', 'Хотим выразить искреннюю благодарность риелтору Роману за профессионализм и внимательное отношение к клиенту. С самого начала сотрудничества он проявил себя как компетентный специалист, который отлично разбирается в рынке недвижимости и учитывает все пожелания.
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (36, 'Клиент Циан', 'Роман - самый крутой риелтор из всех, с кем я до сегодня взаимодействовала! Очень профессиональная и тактичная работа, в том числе по цене, внимание к деталям и всем пожеланиям заказчика, продуманные и комфортные для всех сторон условия в договоре. С удовольствием продолжу сотрудничество!))', 5, true, '2026-02-07 15:02:10+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (37, 'Клиент Циан', 'Хочу поблагодарить Романа за профессиональный подход к своей работе. Всегда был на связи, всегда был готов решать возникающие проблемы. Первый раз покупала квартиру, на все мои вопросы Роман давал грамотные ответы и советы. Провел сделку от начала и до конца, и даже после сделки оказывал помощь. Огромное спасибо!', 5, true, '2025-12-04 17:27:36+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (38, 'Клиент Циан', 'Очень подкованный, грамотный специалист. Максимально погружается в ситуацию, предлагает несколько вариантов, хорошо ориентируется на рынке недвижимости. Приятное общение, мобилен, тактичен.', 5, true, '2025-09-19 10:30:59+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (39, 'Клиент Циан', 'Роман принципиально круче всех риэлторов, с которыми до этого приходилось взаимодействовать. На него действительно можно положиться, он всегда всё чётко и прозрачно поясняет, никогда не нарушает договорённости и не пытается оправдываться "сложным рынком" или какими-то не такими покупателями. Быстро закрыли не самую простую сделку по адекватной цене. Всё рекомендации!', 5, true, '2025-09-13 14:44:11+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (40, 'Клиент Циан', 'Мы с супругом долго искали квартиру под свой бюджет,который соответствовал бы нашим требованиям. Работа с Романом Александровичом  превратила этот процесс в настоящее удовольствие! Он внимательно выслушал наши пожелания, предложил несколько отличных вариантов и помог выбрать идеальный квартиру . 
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (41, 'Самойлов Вячеслав', 'Хочу выразить огромную благодарность   Роману Александровичу за профессиональный подход, терпение и внимание к нашим запросам!  
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (42, 'Клиент Циан', 'Хочу поблагодарить Романа Александровича, он сделал возможное из невозможного, помог приобрести квартиру в ипотеку грубо говоря за сутки, тк на больше времени не было, это было невероятно. Спасибо лучший из лучших 🙏', 5, true, '2024-12-11 16:41:14+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (43, 'Клиент Циан', 'Роман-первоклассный специалист, профи своего дела. Всегда действует в интересах клиента, учитывает все пожелания и рекомендации. Проделал отличную работу начиная с подбора недвижимости и заканчивая ее регистрацией в Росреестре. Рекомендую!', 5, true, '2024-10-29 22:53:39+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (44, 'Клиент Циан', 'Не отвечает на вопросы в лс. Требует личный номер.', 4, true, '2024-10-25 12:18:32+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (45, 'Клиент Циан', 'Роман профессионал своего дела.Быстро помог нам с продажей квартиры,и в выборе покупки квартиры ничего лишнего,все конкретно по делу,буду советовать своим знакомым.', 5, true, '2024-09-27 19:02:28+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (46, 'Клиент Циан', 'Покупали квартиру с помощью Романа. Помог с выбором варианта, на все наши вопросы всегда получали развернутые ответы. Нам очень понравилось работать с Романом: приятный молодой человек и грамотный, компетентный специалист.', 5, true, '2024-07-07 11:45:21+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (47, 'Клиент Циан', 'Роман - это просто восторг! 
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (48, 'Клиент Циан', 'Роман Александрович - настоящий профессионал своего дела. Помог определиться с выбором, подсказал наилучший вариант. Сопровождал на всех этапах сделки, всегда на связи, всегда оперативно отвечает и консультирует по всем нюансам. Всем советую обращаться к Роману Александровичу, не пожалеете!', 5, true, '2024-03-04 19:26:21+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (49, 'Клиент Циан', 'Роман профи своего дела! Ипотеку одобрили в день обращения, сделка прошла четко и быстро.
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (50, 'Табунов Александр', 'Роман специалист высокого уровня, проводили совместную сделку, все прошло замечательно, документы по сделке подготовлены в кратчайшие сроки.
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (51, 'Арицкая Соломея', 'Столько позитивных отзывов🙈 мне риэлтор не понравился совершенно, не компетентен, всю работу на объекте делает собственник. Роман просто стоит и отмалчивается. Зачем он тогда? Ни рулетки, размерами не владеет, в информации путается. Формально выполняет работу, в продаже совершенно не заинтересован. Продавать с ним бы не стала точно!', 3, true, '2024-01-07 23:17:10+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (52, 'Клиент Циан', 'К Роману обратились по совету знакомых, до этого пользоваться услугами агентства при покупке квартиры на первичным рынке даже и не думали. По итогу сотрудничества удалось более точно определиться с объектом покупки, узнать его нюансы, забронировать объект в период, когда этого нельзя было сделать (спасибо связям Романа), получить одобрение (ипотека) в разных банках, растянуть период брони до момента, когда стали готовы выйти на сделку, получить скидку от застройщика. Вся покупка осуществилась при полном взаимодействии Романа и его коллег на всех этапах сделки. Роман всегда был на связи, всегда доброжелателен! Однозначно рекомендую данного специалиста!', 5, true, '2023-12-22 17:49:28+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (53, 'Клиент Циан', 'Роман профессионал своего дела! Очень рада , что именно с ним оформляла сделку и занималась поиском квартиры.  Роман всегда был на связи и на все вопросы спокойно и внятно давал  мне развёрнутые ответы , а я задавала их очень много. Буду рекомендовать его своим друзьям и знакомым.', 5, true, '2023-10-08 17:42:16+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (54, 'Клиент Циан', 'Роман, спасибо большое за такую классную проделанную работу. Как клиент, был очень рад сотрудничеству, когда тебе не банально хотят впарить что нибудь, а узнают истинные потребности. Роман всегда на связи, объяснит, расскажет, покажет, договорится, в общем сделает все, чтобы у клиента сохранились нервные клетки. У меня сделка была полностью удаленная, все моменты и с застройщиком и с банком и с выпуском эцп и со всем остальным взял на себя Роман. Надеюсь еще посотрудничаем.', 5, true, '2023-09-19 08:59:12+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (55, 'Клиент Циан', 'Роман лучший риелтор, быстро продал мою квартиру, буду обращаться снова! советовать своим друзьям, близким!', 5, true, '2023-09-08 15:14:23+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (56, 'Клиент Циан', 'Роман Александрович - просто находка ! 
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (57, 'Клиент Циан', 'Благодарим Романа за оказанную помощь в выборе квартиры. Всегда приятно работать с профессионалами своего дела! Все возникающие вопросы решались быстро. Благодаря Роману получилось сэкономить на страховке и стоимости квартиры. Побольше бы таких специалистов! Екатерина У', 5, true, '2023-03-31 09:35:06+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (58, 'Клиент Циан', 'Хочу написать отзыв о Романе, который, действительно, блестяще помог с определением и выбором квартиры.
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (59, 'Клиент Циан', 'Большое спасибо Рагулину Роману за быстро и качественно проделанную работу. Грамотный специалист знающий свою работу.', 5, true, '2023-01-20 12:03:52+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (60, 'Клиент Циан', 'Профессионал своего дела! Подберет, расскажет, объяснит, всегда приветлив и доброжелателен. Очень довольна работой Романа.', 5, true, '2022-12-14 11:29:47+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (61, 'Гаджиева Аиша', 'Хорошая грамотная работа в подборе квартиры', 5, true, '2022-12-12 23:01:21+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (62, 'Клиент Циан', 'Отличный специалист Роман подобрал варианты недвижимости по всем важным для нас параметрам. Рассказал о всех нюансах в каждом из вариантов. Всегда на связи, в любое время суток. Реально занимается всеми возникающими вопросами по сделке, а не «отфутболивает». Очень позитивное впечатление. Большое спасибо за сотрудничество!', 5, true, '2022-10-12 16:13:24+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (63, 'Клиент Циан', 'Роман помог определиться с недвижимостью. Ответил на все тысячу вопросов оперативно, привлекал команду. Сопровождал нас до конца сделки. Считаем повезло с этим специалистом.', 5, true, '2022-09-30 16:13:41+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (64, 'Клиент Циан', 'Хорошая граммотная работа в подборе и покупке квартиры! Помог со своей коммандой одобрить и разогнать ипотеку до нужного бюджета, а так-же подобрать самые выгодные условия сделки, включая скидку от застройщика. Время посвящает клиенту много и всегда на связи, рекомендую к сотрудничеству!', 5, true, '2022-09-26 21:09:11+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (65, 'Юдина Наталья', 'Хочу выразить Вам свою благодарность за добросовестно проделанную работу: за помощь в выборе квартиры, за подробные разъяснения процесса сделки и за оформление сопутствующих документов. Благодаря Вам выбрала в кратчайшие сроки просторную квартиру с лучшими для меня условиями ипотеки. Мне очень понравилась сотрудничать с таким профессионалом как Вы! Роман, спасибо Вам огромное за доброту, за ответственность, за отзывчивость, за тонкий юмор и за то, что всегда были на связи. Желаю Вам больших успехов в Вашей профессиональной деятельности!', 5, true, '2022-08-23 11:31:40+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (66, 'Клиент Циан', 'Роман, продавал мою квартиру. Сказать, что хороший риелтор, ничего не сказать. Он продал мою квартиру дороже, чем я планировал. И за короткий срок. Спасибо огромное. 
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (67, 'Инна', 'Однозначно рекомендую Романа Александровича- прекрасный специалист!
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (68, 'Женя', 'Благодарю риелтора Романа за безупречную помощь в покупке квартиры мечты! Он оперативно нашел отличные варианты по нашим критериям (район, площадь, цена), организовал удобные просмотры и мастерски провел переговоры. Роман — суперпрофи: всегда на связи, честный, внимательный к деталям. Настоятельно рекомендую лучший риелтор!', 5, true, '2026-04-10 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (69, 'Александр', 'Очень довольны работой риелтора Романа. Всё прошло быстро, чётко и без лишних вопросов.
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (70, 'Наталья', 'Выражаю огромную благодарность за проделанную работу Роману. За весь период работы с ним, он проявил себя грамотным, понимающим весь процесс по оформлению сделки с недвижимостью с учётом требований действующего законодательства РФ. Тактичен, вежлив, пунктуален. Всегда на связи. Благодарю его и компанию "Этажи" за труды.', 5, true, '2026-01-24 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (71, 'Ирина', 'Отзывчивость, Ответственность, Профессионализм, Пунктуальность. Прекрасный специалист,  отзывчивый человек, профессионал в своём деле! На всех этапах сделки по покупке квартиры был на связи, консультировал, советовал и помогал. Отличный риелтор!', 5, true, '2025-12-04 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (72, 'Наталь', 'С Романом мы прошли не простой путь к покупке квартиры. Спасибо большое за поддержку, за помощь и качество работы! Все на вы высоте! 
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (73, 'Артем', 'Роман на голову выше всех остальных специалистов, с которыми когда-либо приходилось иметь дело. Быстро и по адекватной цене закрыл не самую простую сделку - без длинных рассказов про то, "какой сейчас рынок сложный и как тяжело всё продаётся". Безупречная коммуникация, всё чётко и прозрачно. Все рекомендации!', 5, true, '2025-09-12 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (74, 'Рахимова', 'Мы с супругом долго искали квартиру, который соответствовал бы нашим требованиям. Работа с Романом Александровичем превратила этот процесс в настоящее удовольствие! Он внимательно выслушал наши пожелания, предложил несколько отличных вариантов и помог выбрать идеальную квартиру Благодаря профессионализму риэлтора, оформлению документов уделили минимум времени, так как всё было подготовлено заранее. Он всегда был на связи, давал чёткие разъяснения по каждому этапу сделки и помог разобраться со всеми нюансами.  Благодаря Роману,мы нашли квартиру своей мечты! Очень рекомендуем этого специалиста всем, кто ищет надёжного, внимательного и честного риэлтора! Он работает в пользу клиента спасибо огромное и не только профи своего дела, и ещё очень хороший и отзывчивый человек, нам повезло с супругом что встретили именно вас!', 5, true, '2025-09-11 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (75, 'Татьяна', 'Обратились к Роману за помощью в приобретении квартиры. Не ожидали, что за довольно короткий промежуток времени найдем подходящий вариант. Роман- настоящий профессионал своего дела! Очень грамотный специалист. Мы доверились Роману с первой встречи. Сразу понимает желание клиента, советует, предостерегает, сообщает все нюансы, ответственно подходит к своей работе. Приятно было работать с таким профессионалом, спасибо большое!', 5, true, '2025-02-13 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (76, 'Рамсият', 'Хотела поблагодарить Романа , он мне очень помог со сделкой( покупкой в строящем доме квартиры )! Все быстро четко! А главное результат!', 5, true, '2024-12-11 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (77, 'Александра', 'Огромное спасибо Роману Александровичу за оперативную и, самое главное, качественную работу. Ему удалось найти мне ту квартиры, в которую я влюбилась с первого взгляда. Во-первых, с самого начала работы со мной он четко понял, какая именно квартира мне нужна. И подобрал те варианты квартир, которые подходили под мои предпочтения и бюджет. Во-вторых, про каждую из них подробно рассказал, записал на встречи в офисы продаж и помог определиться с выбором. Очень оперативно были подготовлены все необходимые документы. Роман всегда находился на связи, не возникало никаких трудностей и вопросов в подписании документов и заключении сделки.', 5, true, '2024-10-29 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (78, 'Раиса', 'Роман настоящий профессионал своего дела очень быстро помог нам с продажей квартиры и в выборе квартиры так же  , подробно рассказывал все преимущества каждого объекта.Спасибо большое Роман.Буду советовать своим знакомым.', 5, true, '2024-09-27 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (79, 'Роман Тверитин', 'Оформлял строительство дома и участок в ипотеку. И это тот человек который вам нужен. Он профессионал своего дела. Всегда был на связи,в любой проблемной ситуации помогал. Доходчиво объяснил как и что нужно делать и когда. Работает 24 часа в сутки.  В общем я очень доволен его работой. Выражаю огромную благодарность и искреннее спасибо за помощь и потраченные нервы. Рекомендую без всякого сомнения. И ещё раз спасибо.', 5, true, '2024-06-17 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (80, 'Нургиза', 'Хочу отметить профессиональную работу Романа Александровича! Сопровождал мою сделку от момента выбора до подписания бумаг! Всегда был на связи,грамотно отвечал на вопросы,был пунктуален) Теперь я счастливый обладатель квартиры)))👍 
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (81, 'Алена', 'Роман Александрович - настоящий профессионал, очень помог в таком важном и сложном вопросе, как выбор и приобретение недвижимости. Всегда на связи, оперативно отвечает на все возникающие вопросы, подробно консультирует, все четко рассказывает и объясняет. Ездил со мной на все объекты, помог определиться с выбором. Большое спасибо ему! Теперь по всем вопросам недвижимости будем обращаться к Роману! Принимает участие во всех этапах, напоминает все важные моменты. Очень грамотный специалист и просто хороший человек.', 5, true, '2024-03-04 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (82, 'Наталья', 'Огромная благодарность Роману за помощь с продажей квартиры! Находясь за тысячи километров было тревожно и ситуация была сложно, но Роман выполнил свою работу на все 100% Всё прошло отлично!', 5, true, '2024-01-12 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (83, 'Наргиза', 'Не пожалела что обратилась именно Роману Александровичу, рекомендую однозначно!', 5, true, '2024-01-11 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (84, 'Константин', 'Спасибо огромное Роману! Помог купить квартиру за минимальный срок с максимально выходными условиями! Всегда на связи, проконсультирует. Всё очень чётко, оперативно!  Лучший риелтор!!', 5, true, '2023-09-26 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (85, 'Альбина', 'Хочу выразить свою благодарность Роману, очень профессиональный, сервис на высоте, даже с учетом того что мне нужно было срочно найти квартиру и еще куча важных параметров. Все удалось. Спасибо большое!', 5, true, '2023-09-08 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (86, 'Малика', 'Всё быстро, чётко и легко. Роман всегда был на связи, не побоюсь сказать, что 24/7.  Любой наш вопрос не был оставлен без ответа.', 5, true, '2023-07-14 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (87, 'Жанна Павловна', 'Роман Александрович - просто находка !!! Благодарю за произведенную работу! Оперативно, лояльно, комфортно, без напоминаний, всегда на связи! На все вопросы отвечает раскрыто, подскажет, как лучше! Помогает и ориентируется на выбор, как для себя! Лучший специалист!', 5, true, '2023-05-22 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (88, 'Екатерина У', 'Благодарим Романа за оказанную помощь в выборе квартиры. Всегда приятно работать с профессионалами своего дела! Все возникающие вопросы решались быстро. Благодаря Роману получилось сэкономить на страховке и стоимости квартиры. Побольше бы таких специалистов!', 5, true, '2023-03-31 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (89, 'Мария', 'Выражаю благодарность Менеджеру Рагулину Роману. Очень  компетентный, сразу подсказал ипотечные программы, вёл сделку от и до, всегда был  на связи, где то посоветовал, организовал просмотр шоурума,  я практически не выходя из дома приобрела квартиру, спасибо за такие комфортные условия оформления квартиры 
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (90, 'Тимур', 'Хочу написать отзыв о Романе, который, действительно, блестяще помог с определением и выбором квартиры.
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (91, 'Залина', 'Хочу выразить огромную благодарность Рагулину  Роману за помощь в подборе и приобретении жилья . Давно хотела приобрести недвижимость , но боялась не решалась. Это просто какое-то новогоднее чудо, повстречать специалиста который так ответственно относится к своему делу, я уже молчу что всегда на связи 24/7.СПАСИБО!!!', 5, true, '2023-01-04 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (92, 'Екатерина', 'Добрый день. Работала с Романом от начала и до конца. Впервые столкнулась с менеджером, который всегда на связи, который отвечает на все вопросы в любое время суток, помогал абсолютно во всем. Объяснял все тонкости процесса понятным языком, советовал лучшие решения. Огромная благодарность ему за такую работу!', 5, true, '2022-12-14 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (93, 'Айшат', 'Качестве услуги отличное, все было идеально и быстро выполнено', 5, true, '2022-12-12 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (94, 'Наталья', 'Выражаю благодарность Роману за оказанную помощь в подборе объекта и проведении всех этапов сделки. Внимателен, сосредоточен, располагает актуальной информацией о текущей ситуации на рынке недвижимости, даёт объективную оценку, основываясь на аналитике рынка. Рекомендую к сотрудничеству! Желаю успехов и карьерного роста!', 5, true, '2022-11-21 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (95, 'Алексей', 'Обращались для продажи по переуступке квартиры и последующей покупки новой. Обе сделки прошли успешно, Роман всегда оставался на связи, консультировал по всем возникающим вопросам. Благодарим за проделанную работу .', 5, true, '2022-10-22 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (96, 'Владимир', 'Позвонили Роману по вопросу приобретения студии в Москве. Всё организовал: встречу в офисе, внимательно выслушал наши требования и рассказал о программе субсидирования застройщиком нового жилья. Показал варианты. Всё по делу и подробно рассказал. В итоге мы  приобрели евродвушку с меньшим процентом и ежемесячным платежом. Выбором довольны.', 5, true, '2022-09-30 03:00:00+03');
INSERT INTO public.reviews (id, client_name, text, rating, is_published, created_at) VALUES (97, 'Наталья', 'Хочу выразить благодарность Роману за проделанную работу в организации покупки квартиры, оформлении всех сопутствующих документов и грамотное ведение сделки. Помог определиться с выбором квартиры, очень подробно объяснял весь процесс заключения сделки, в связи, с чем не возникало лишних вопросов. На всех этапах нашего сотрудничества Роман показал себя как очень добрый, ответственный, отзывчивый и профессиональный человек, знающий свое дело!  Впечатление о работе с ним самые положительные. Обязательно буду рекомендовать знакомым. Желаю дальнейшего развития и хороших клиентов!', 5, true, '2022-08-12 03:00:00+03');
